// Parse Twilio webhook payload (form-urlencoded) avec validation anti-injection
var data = $input.first().json;
var body = data.body || data;

// Regex de validation pour les champs Twilio
var CALLSID_RE = /^CA[0-9a-f]{32}$/i;
var PHONE_RE = /^\+?[0-9]{6,15}$/;

// Nettoyer : ne garder que les caractères attendus
function sanitizePhone(p) { return String(p || '').replace(/[^+0-9]/g, '').substring(0, 16); }
function sanitizeCallSid(s) { return String(s || '').replace(/[^a-zA-Z0-9]/g, '').substring(0, 34); }
function sanitizeText(t) { return String(t || '').replace(/'/g, "''").substring(0, 2000); }

var callSid = sanitizeCallSid(body.CallSid);
var from = sanitizePhone(body.From);
var to = sanitizePhone(body.To);
var callStatus = String(body.CallStatus || '').replace(/[^a-z-]/gi, '').substring(0, 30);
var speechResult = sanitizeText(body.SpeechResult);
var digits = String(body.Digits || '').replace(/[^0-9*#]/g, '').substring(0, 20);
var isCallback = !!speechResult || !!digits;

return [{json: {
  callSid,
  from,
  to,
  callStatus,
  speechResult,
  digits,
  isCallback
}}];

// Premier appel : message d'accueil + Gather — DYNAMIQUE depuis config
var callSid = $('02. Parser Twilio').first().json.callSid;
var from = $('02. Parser Twilio').first().json.from;

// Charger la config
var cfg = $('02b. Load Config').first().json || {};
var welcomeMsg = cfg.welcome_message || cfg.welcomeMessage || ((cfg.company_name || cfg.companyName || 'Notre entreprise') + ', bonjour ! Comment puis-je vous aider ?');
var voiceName = cfg.voice_name || cfg.voiceName || 'Polly.Lea-Neural';
var language = cfg.language || 'fr-FR';

// Echappement XML obligatoire pour TwiML
function xmlEscape(s) {
  return String(s || '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&apos;');
}

welcomeMsg = xmlEscape(welcomeMsg);

// Valider que le message n'est pas vide apres echappement
if (!welcomeMsg.trim()) {
  welcomeMsg = 'Bonjour, comment puis-je vous aider ?';
}

var twiml = '<?xml version="1.0" encoding="UTF-8"?>\n'
  + '<Response>\n'
  + '  <Say voice="' + voiceName + '" language="' + language + '">' + welcomeMsg + '</Say>\n'
  + '  <Gather input="speech" language="' + language + '" speechTimeout="auto" timeout="8" enhanced="true" bargeIn="true" action="https://n8n.talosprimes.com/webhook/twilio-inbound-voice" method="POST"/>\n'
  + '  <Gather input="speech" language="' + language + '" speechTimeout="auto" timeout="15" enhanced="true" bargeIn="true" action="https://n8n.talosprimes.com/webhook/twilio-inbound-voice" method="POST">\n'
  + '    <Say voice="' + voiceName + '" language="' + language + '">Vous \u00eates toujours l\u00e0 ? N\'h\u00e9sitez pas \u00e0 me poser votre question.</Say>\n'
  + '  </Gather>\n'
  + '  <Say voice="' + voiceName + '" language="' + language + '">Je n\'ai pas entendu votre r\u00e9ponse. Au revoir et bonne journ\u00e9e !</Say>\n'
  + '</Response>';

return [{ json: { twiml, callSid, from } }];

// Callback avec SpeechResult
var prev = $('02. Parser Twilio').first().json;
var speechResult = prev.speechResult;
var callSid = prev.callSid;
var from = prev.from;

if (!speechResult || speechResult.trim() === '') {
  return [{json: { callSid, from, speechResult: '', hasText: false }}];
}

return [{json: { callSid, from, speechResult: speechResult.trim(), hasText: true }}];

// Pas de texte detecte, on relance l'ecoute — voix dynamique
var cfg = $('02b. Load Config').first().json || {};
var voiceName = cfg.voice_name || cfg.voiceName || 'Polly.Lea-Neural';
var language = cfg.language || 'fr-FR';
var callSid = $('02. Parser Twilio').first().json.callSid;
var from = $('02. Parser Twilio').first().json.from;

var twiml = '<?xml version="1.0" encoding="UTF-8"?>\n'
  + '<Response>\n'
  + '  <Say voice="' + voiceName + '" language="' + language + '">Excusez-moi, je n\'ai pas bien compris. Pouvez-vous r\u00e9p\u00e9ter ?</Say>\n'
  + '  <Gather input="speech" language="' + language + '" speechTimeout="auto" timeout="8" enhanced="true" bargeIn="true" action="https://n8n.talosprimes.com/webhook/twilio-inbound-voice" method="POST"/>\n'
  + '  <Gather input="speech" language="' + language + '" speechTimeout="auto" timeout="15" enhanced="true" bargeIn="true" action="https://n8n.talosprimes.com/webhook/twilio-inbound-voice" method="POST">\n'
  + '    <Say voice="' + voiceName + '" language="' + language + '">Je suis toujours l\u00e0, n\'h\u00e9sitez pas.</Say>\n'
  + '  </Gather>\n'
  + '  <Say voice="' + voiceName + '" language="' + language + '">Merci de votre appel. Au revoir !</Say>\n'
  + '</Response>';

return [{ json: { twiml, callSid, from } }];

// Mode admin désactivé — tout en mode standard
var speechResult = $('06. Extract Speech').first().json.speechResult;
var callSid = $('06. Extract Speech').first().json.callSid;
var from = $('06. Extract Speech').first().json.from;

return [{ json: {
  callSid,
  from,
  speechResult,
  isAdminPhrase: false,
  isAdminByPhone: false,
  mode: 'standard'
} }];

// Build Prompt — OPTIMIZED for low latency
var prev = $('10. Detect Admin').first().json;
var cfg = $('02b. Load Config').first().json || {};
var speechResult = prev.speechResult;
var callSid = prev.callSid;
var from = prev.from;

// === PARSE COMBINED QUERY (session + kb + history in one shot) ===
var session = {};
var knowledgeRows = [];
var historyRows = [];
try {
  var allRows = $('11x. Combined Query').all();
  for (var i = 0; i < allRows.length; i++) {
    var r = allRows[i].json || allRows[i];
    if (r._type === 'session') session = r;
    else if (r._type === 'kb') knowledgeRows.push(r);
    else if (r._type === 'history') historyRows.push(r);
  }
} catch(e) {}

var tenantId = (session && session.tenant_id) ? session.tenant_id : (cfg.tenant_id || '');
var agentName = cfg.agent_name || cfg.agentName || "l'assistante";
var companyName = cfg.company_name || cfg.companyName || 'Notre entreprise';
var systemPromptAddon = cfg.system_prompt_addon || cfg.systemPromptAddon || '';
var knowledgeBaseText = cfg.knowledge_base || cfg.knowledgeBase || '';
var customSystemPrompt = cfg.system_prompt || cfg.systemPrompt || '';
var maxTokens = Math.min(parseInt(cfg.max_tokens || cfg.maxTokens || 120) || 120, 150);
var temperature = (cfg.temperature != null && cfg.temperature !== '') ? parseFloat(cfg.temperature) : 0.3;
var voiceName = cfg.voice_name || cfg.voiceName || 'Polly.Lea-Neural';
var language = cfg.language || 'fr-FR';

// Client info
var clientInfo = '';
if (session && session.nom) {
  clientInfo = 'CLIENT: ' + (session.prenom || '') + ' ' + session.nom;
  if (session.email) clientInfo += ' (' + session.email + ')';
  clientInfo += '. Salue-le par son prenom.';
} else {
  clientInfo = 'NOUVEAU NUMERO: ' + from + '. Appelle create_lead immediatement.';
}

// Historique
var conversationHistory = '';
var exchanges = [];
for (var i = 0; i < historyRows.length; i++) {
  var notes = String(historyRows[i].notes || '');
  var qM = notes.match(/Q: (.+?) - R: /);
  var rM = notes.match(/R: (.+)$/);
  if (qM && rM) exchanges.push('Client: ' + qM[1].substring(0,150) + '\n' + agentName + ': ' + rM[1].substring(0,200));
}
if (exchanges.length > 0) conversationHistory = '\n--- HISTORIQUE ---\n' + exchanges.join('\n') + '\n---\n';

// Knowledge base
var faqContext = knowledgeBaseText || '';
if (knowledgeRows.length > 0) {
  var byCategorie = {};
  for (var i = 0; i < knowledgeRows.length; i++) {
    var r = knowledgeRows[i];
    if (!r.contenu) continue;
    var cat = r.categorie || 'autre';
    if (!byCategorie[cat]) byCategorie[cat] = [];
    byCategorie[cat].push('- ' + (r.titre || '') + ': ' + r.contenu);
  }
  var sections = [];
  var catOrder = ['info_entreprise','services','tarifs','faq','politiques','actions','autre'];
  for (var j = 0; j < catOrder.length; j++) {
    if (byCategorie[catOrder[j]]) sections.push(byCategorie[catOrder[j]].join('\n'));
  }
  var structured = sections.join('\n');
  if (structured) faqContext = faqContext ? (faqContext + '\n' + structured) : structured;
}

// Truncate KB aggressively for speed
var hasHistory = exchanges.length > 0;
var maxKB = hasHistory ? 1200 : 2000;
if (faqContext.length > maxKB) faqContext = faqContext.substring(0, maxKB) + '\n[...]';

// Build system prompt
var systemPrompt = '';
if (customSystemPrompt) {
  systemPrompt = customSystemPrompt;
  systemPrompt += '\n\n' + clientInfo;
  if (faqContext) systemPrompt += '\n\nBASE:\n' + faqContext;
  if (systemPromptAddon) systemPrompt += '\n' + systemPromptAddon;
} else {
  systemPrompt = 'Tu es ' + agentName + ', assistant(e) tel de ' + companyName + '. Chaleureuse, naturelle, pro. Vouvoie TOUJOURS.\n\n'
  + clientInfo + '\n\n';
  if (faqContext) systemPrompt += 'BASE DE CONNAISSANCES:\n' + faqContext + '\n\n';
  systemPrompt += 'REGLES:\n'
  + '- Parle naturellement, comme au telephone. Pas de listes ni markdown.\n'
  + '- Reponds completement mais concisement.\n'
  + '- UNE question a la fois, puis ecoute.\n'
  + '- Ne te repete JAMAIS. Ne redis JAMAIS bonjour.\n'
  + '- Nouveau numero = appelle create_lead avec le telephone.\n'
  + '- Consulte ta base AVANT de repondre.\n'
  + '- Si pas dans la base: "Je note, un collegue vous recontactera sous 24h."\n'
  + '- Termine en demandant si autre chose.\n';
  if (systemPromptAddon) systemPrompt += '\n' + systemPromptAddon;
}

// Tools — only 2 essential ones for speed
var tools = [
  {type:"function","function":{name:"create_lead",description:"Enregistrer un prospect.",parameters:{type:"object",properties:{telephone:{type:"string"},nom:{type:"string"},notes:{type:"string"}},required:["telephone"]}}},
  {type:"function","function":{name:"create_devis",description:"Creer un devis.",parameters:{type:"object",properties:{description:{type:"string"},montant_ht:{type:"number"}},required:["description"]}}}
];

// Messages
var messages = [{role:"system",content:systemPrompt}];
for (var h = 0; h < exchanges.length && h < 2; h++) {
  var parts = exchanges[h].split('\n');
  if (parts.length >= 2) {
    messages.push({role:"user",content:parts[0].replace(/^Client: /,'').substring(0,150)});
    messages.push({role:"assistant",content:parts[1].replace(new RegExp('^' + agentName + ': '),'').substring(0,200)});
  }
}
messages.push({role:"user",content:speechResult});

return [{json:{
  systemPrompt:systemPrompt,
  messages:JSON.stringify(messages),
  tools:JSON.stringify(tools),
  tenantId:tenantId,
  callSid:callSid,
  from:from,
  speechResult:speechResult,
  maxTokens:maxTokens,
  temperature:temperature,
  voiceName:voiceName,
  language:language,
  agentName:agentName,
  companyName:companyName
}}];

// Build TwiML Response — ROBUST version with error handling
var config, callSid, from, to, speechResult;
try {
  config = $('02b. Load Config').first().json;
  var parser = $('02. Parser Twilio').first().json;
  callSid = parser.callSid || '';
  from = parser.from || '';
  to = parser.to || '';
  speechResult = '';
  try { speechResult = $('07. Extract Speech').first().json.speechResult || ''; } catch(e) {}
} catch (e) {
  // Absolute fallback if we can't even load config
  return [{json: {
    twiml: '<?xml version=\"1.0\" encoding=\"UTF-8\"?><Response><Say language=\"fr-FR\" voice=\"Polly.Celine\">Excusez-moi, je rencontre un problème technique. Veuillez réessayer dans quelques instants.</Say><Hangup/></Response>',
    callSid: '', from: '', to: '', tenantId: '', aiReply: '', speechResult: '', isProspect: false, needsEscalation: false
  }}];
}

var tenantId = config.tenant_id || '';
var voice = config.voice_name || 'Polly.Lea-Neural';
var language = config.language || 'fr-FR';
var callbackUrl = 'https://n8n.talosprimes.com/webhook/twilio-inbound-voice';

// Try to get OpenAI response
var aiReply = '';
var toolCalls = null;
try {
  var openaiRaw = $('13. OpenAI Chat').first().json;
  if (openaiRaw && openaiRaw.choices && openaiRaw.choices[0]) {
    var msg = openaiRaw.choices[0].message;
    if (msg) {
      aiReply = msg.content || '';
      toolCalls = msg.tool_calls || null;
    }
  }
} catch (e) {
  // OpenAI failed — use fallback
  aiReply = '';
}

// If there was a tool call response, try to get it
if (!aiReply) {
  try {
    var toolResult = $('25. OpenAI Tool Result').first().json;
    if (toolResult && toolResult.choices && toolResult.choices[0]) {
      aiReply = toolResult.choices[0].message.content || '';
    }
  } catch (e) {}
}

// If still no reply, use a friendly fallback
if (!aiReply || aiReply.trim() === '') {
  aiReply = "Excusez-moi, je n'ai pas pu traiter votre demande. Pouvez-vous reformuler votre question ?";
}

// Clean the reply for TwiML
aiReply = aiReply.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');

// Detect prospect/escalation
var isProspect = /devis|tarif|prix|combien|intéress|souscrire|acheter|commander/i.test(speechResult);
var needsEscalation = /humain|personne|responsable|directeur|plainte|avocat|urgence/i.test(speechResult);
var isGoodbye = /au revoir|bonne journ|merci.*revoir|c'est tout|j'ai fini/i.test(speechResult);

// Build TwiML
var twiml = '<?xml version=\"1.0\" encoding=\"UTF-8\"?><Response>';

if (isGoodbye) {
  twiml += '<Say language=\"' + language + '\" voice=\"' + voice + '\">' + aiReply + '</Say>';
  twiml += '<Hangup/>';
} else if (callbackUrl) {
  twiml += '<Gather input=\"speech\" speechTimeout=\"auto\" timeout=\"10\" enhanced=\"true\" bargeIn=\"true\" action=\"' + callbackUrl + '\" method=\"POST\">';
  twiml += '<Say language=\"' + language + '\" voice=\"' + voice + '\">' + aiReply + '</Say>';
  twiml += '</Gather>';
  twiml += '<Say language=\"' + language + '\" voice=\"' + voice + '\">Je suis toujours là si vous avez d\'autres questions.</Say>';
  twiml += '<Gather input=\"speech\" speechTimeout=\"auto\" timeout=\"10\" enhanced=\"true\" bargeIn=\"true\" action=\"' + callbackUrl + '\" method=\"POST\">';
  twiml += '<Say language=\"' + language + '\" voice=\"' + voice + '\">N\'hésitez pas à me poser votre question.</Say>';
  twiml += '</Gather>';
} else {
  twiml += '<Say language=\"' + language + '\" voice=\"' + voice + '\">' + aiReply + '</Say>';
  twiml += '<Hangup/>';
}

twiml += '</Response>';

return [{json: {
  twiml: twiml,
  callSid: callSid,
  from: from,
  to: to,
  tenantId: tenantId,
  aiReply: aiReply.replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"'),
  speechResult: speechResult,
  isProspect: isProspect,
  needsEscalation: needsEscalation
}}];

// SAFETY: Si OpenAI n'a pas répondu (timeout/erreur), retourner une réponse par défaut
var openaiResponse = $input.first().json;
if (!openaiResponse || !openaiResponse.choices || !openaiResponse.choices[0]) {
  var prev = $('12. Build Prompt').first().json;
  return [{ json: {
    hasToolCall: false,
    aiReply: "Excusez-moi, j'ai eu un petit souci technique. Pouvez-vous répéter votre demande ?",
    callSid: prev.callSid || '',
    from: prev.from || '',
    speechResult: prev.speechResult || '',
    isAdmin: false,
    clientName: '',
    clientEmail: '',
    tenantId: prev.tenantId || ''
  } }];
}
// Suite du parsing normal (openaiResponse déjà validé ci-dessus)
var prev = $('12. Build Prompt').first().json;
if (!prev || !prev.systemPrompt) throw new Error('Build Prompt: donnees manquantes. Le node 12 n a pas retourne de systemPrompt.');
var message = openaiResponse.choices?.[0]?.message;
var finishReason = openaiResponse.choices?.[0]?.finish_reason;

// === FONCTIONS DE VALIDATION ===
var UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
var PHONE_RE = /^\+?[0-9]{6,15}$/;
var EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

function sanitizePhone(p) { return String(p || '').replace(/[^+0-9]/g, '').substring(0, 16); }
function validateNum(n, min, max) { var v = parseFloat(n); return (Number.isFinite(v) && v >= min && v <= max) ? v : 0; }
function safe(s, maxLen) { return String(s || '').substring(0, maxLen || 500); }
function interpolateSQL(q, p) { return q.replace(/\$(\d+)/g, function(_, i) { var v = p[parseInt(i) - 1]; if (v === null || v === undefined) return 'NULL'; if (typeof v === 'number') return String(v); return "'" + String(v).replace(/'/g, "''") + "'"; }); }

if (finishReason === 'tool_calls' && message?.tool_calls?.length > 0) {
  var toolCall = message.tool_calls[0];
  var toolName = toolCall.function.name;
  var toolArgs = JSON.parse(toolCall.function.arguments || '{}');
  var toolCallId = toolCall.id;
  var tenantId = prev.tenantId || '';

  var ALLOWED_TOOLS = ['create_lead', 'search_client', 'create_client', 'create_invoice', 'create_bon_commande', 'list_recent_leads', 'update_lead', 'update_client', 'list_clients', 'list_invoices', 'list_devis', 'update_invoice_status', 'create_devis', 'schedule_callback'];
  if (!ALLOWED_TOOLS.includes(toolName)) throw new Error('Tool non autorisé: ' + toolName);

  var sqlQuery = '';
  var sqlParams = [];

  if (toolName === 'create_lead') {
    var nom = safe(toolArgs.nom, 100);
    var prenom = safe(toolArgs.prenom, 100);
    var email = toolArgs.email && EMAIL_RE.test(toolArgs.email) ? safe(toolArgs.email, 255) : '';
    var tel = sanitizePhone(toolArgs.telephone || prev.from);
    var notes = safe(toolArgs.notes, 500);
    if (!tel) throw new Error('Téléphone requis pour create_lead');
    sqlQuery = `INSERT INTO leads (id, tenant_id, nom, prenom, email, telephone, source, statut, notes, created_at, updated_at)
      SELECT gen_random_uuid(), COALESCE(NULLIF($1, '')::uuid, (SELECT id FROM tenants LIMIT 1)), $2, $3, $4, $5, 'telephone_ia', 'nouveau', $6, NOW(), NOW()
      WHERE NOT EXISTS (SELECT 1 FROM leads WHERE telephone LIKE '%' || RIGHT($5, 9) || '%' AND statut != 'abandonne')
      RETURNING id, nom, prenom, telephone`;
    sqlParams = [tenantId, nom, prenom, email, tel, notes];
  } else if (toolName === 'search_client') {
    var q = safe(toolArgs.query, 100);
    if (!q) throw new Error('Query requis pour search_client');
    sqlQuery = `SELECT id, nom, prenom, email, telephone, raison_sociale, type, statut FROM client_finals WHERE nom ILIKE '%' || $1 || '%' OR prenom ILIKE '%' || $1 || '%' OR telephone LIKE '%' || $1 || '%' OR email ILIKE '%' || $1 || '%' LIMIT 5`;
    sqlParams = [q];
  } else if (toolName === 'create_client') {
    var email = toolArgs.email && EMAIL_RE.test(toolArgs.email) ? safe(toolArgs.email, 255) : '';
    if (!email) throw new Error('Email valide requis pour create_client');
    var type = ['b2b', 'b2c'].includes(toolArgs.type) ? toolArgs.type : 'b2c';
    sqlQuery = `INSERT INTO client_finals (id, tenant_id, type, nom, prenom, email, telephone, raison_sociale, statut, created_at, updated_at)
      VALUES (gen_random_uuid(), COALESCE(NULLIF($7, '')::uuid, (SELECT id FROM tenants LIMIT 1)), $1, $2, $3, $4, $5, $6, 'actif', NOW(), NOW())
      RETURNING id, nom, prenom, email`;
    sqlParams = [type, safe(toolArgs.nom, 100), safe(toolArgs.prenom, 100), email, sanitizePhone(toolArgs.telephone), safe(toolArgs.raison_sociale, 255), tenantId];
  } else if (toolName === 'create_invoice') {
    var ht = validateNum(toolArgs.montant_ht, 0, 999999);
    var tva = validateNum(toolArgs.tva_taux || 20, 0, 100);
    var ttc = ht * (1 + tva / 100);
    var clientQ = safe(toolArgs.client_name_or_phone, 100);
    if (!clientQ || ht <= 0) throw new Error('Client et montant requis pour create_invoice');
    var numFacture = 'FA-' + Date.now();
    sqlQuery = `INSERT INTO invoices (id, tenant_id, type, client_final_id, numero_facture, date_facture, date_echeance, montant_ht, montant_ttc, tva_taux, description, statut, created_at, updated_at)
      SELECT gen_random_uuid(), COALESCE(NULLIF($7, '')::uuid, (SELECT id FROM tenants LIMIT 1)), 'facture_client_final',
        (SELECT id FROM client_finals WHERE nom ILIKE '%' || $1 || '%' OR telephone LIKE '%' || $1 || '%' LIMIT 1),
        $2, NOW(), NOW() + INTERVAL '30 days', $3, $4, $5, $6, 'brouillon', NOW(), NOW()
      RETURNING id, numero_facture, montant_ht, montant_ttc, statut`;
    sqlParams = [clientQ, numFacture, ht, parseFloat(ttc.toFixed(2)), tva, safe(toolArgs.description, 500), tenantId];
  } else if (toolName === 'create_bon_commande') {
    var ht = validateNum(toolArgs.montant_ht, 0, 999999);
    var tva = validateNum(toolArgs.tva_taux || 20, 0, 100);
    var ttc = ht * (1 + tva / 100);
    var clientQ = safe(toolArgs.client_name_or_phone, 100);
    if (!clientQ || ht <= 0) throw new Error('Client et montant requis pour create_bon_commande');
    var numBdc = 'BDC-' + Date.now();
    sqlQuery = `INSERT INTO bons_commande (id, tenant_id, client_final_id, numero_bdc, date_bdc, montant_ht, montant_ttc, tva_taux, description, statut, created_at, updated_at)
      SELECT gen_random_uuid(), COALESCE(NULLIF($7, '')::uuid, (SELECT id FROM tenants LIMIT 1)),
        (SELECT id FROM client_finals WHERE nom ILIKE '%' || $1 || '%' OR telephone LIKE '%' || $1 || '%' LIMIT 1),
        $2, NOW(), $3, $4, $5, $6, 'brouillon', NOW(), NOW()
      RETURNING id, numero_bdc, montant_ht, montant_ttc, statut`;
    sqlParams = [clientQ, numBdc, ht, parseFloat(ttc.toFixed(2)), tva, safe(toolArgs.description, 500), tenantId];
  } else if (toolName === 'list_recent_leads') {
    var limit = Math.min(Math.max(parseInt(toolArgs.limit) || 5, 1), 20);
    var statut = ['nouveau', 'contacte', 'converti', 'abandonne'].includes(toolArgs.statut) ? toolArgs.statut : null;
    if (statut) {
      sqlQuery = `SELECT id, nom, prenom, telephone, email, statut, source, created_at FROM leads WHERE statut = $1 ORDER BY created_at DESC LIMIT $2`;
      sqlParams = [statut, limit];
    } else {
      sqlQuery = `SELECT id, nom, prenom, telephone, email, statut, source, created_at FROM leads ORDER BY created_at DESC LIMIT $1`;
      sqlParams = [limit];
    }
  } else if (toolName === 'update_lead') {
    var q = safe(toolArgs.lead_id_or_phone, 100);
    if (!q) throw new Error('ID ou téléphone requis pour update_lead');
    var sets = [];
    var params = [q];
    var idx = 2;
