  var keywords = motsCles.split(',').map(function(k) { return k.trim(); }).filter(function(k) { return k.length > 2; });

  var score = 0;
  for (var j = 0; j < keywords.length; j++) {
    if (speechResult.indexOf(keywords[j]) !== -1) {
      score += keywords[j].length; // longer keyword = better match
    }
  }

  if (score > bestScore) {
    bestScore = score;
    bestMatch = row;
  }
}

